import React, { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true); // Default to true, as we're loading user from localStorage

  // Load user from localStorage on mount
  useEffect(() => {
    const loadUser = async () => { // Made async to demonstrate potential async operations
      try {
        // Simulate a small delay for initial loading, common in real apps
        // await new Promise(resolve => setTimeout(resolve, 100)); 

        const storedUser = localStorage.getItem("user");
        if (storedUser) {
          const parsedUser = JSON.parse(storedUser);
          // Optional: You might want to validate the token/user data with an API call here
          // if (parsedUser.token) {
          //   const isValid = await checkTokenValidity(parsedUser.token); // Your API call
          //   if (isValid) {
          //     setUser(parsedUser);
          //   } else {
          //     localStorage.removeItem("user"); // Token invalid, clear it
          //   }
          // } else {
              setUser(parsedUser); // If no token or simple user object
          // }
        }
      } catch (error) {
        console.error("AuthContext: Failed to parse user from localStorage or validate token", error);
        localStorage.removeItem("user"); // Clear any malformed user data
      } finally {
        setLoading(false); // Always set loading to false after initial check
        console.log("AuthContext: Initial loading complete."); // Debug log
      }
    };
    loadUser();
  }, []); // Empty dependency array means this runs once on mount

  const login = async (email, password) => {
    setLoading(true); // Indicate that a login attempt is in progress
    console.log(`AuthContext: Attempting login for ${email}`); // Debug log
    try {
      // --- IMPORTANT: Replace this simulated API call with your actual backend API call ---
      await new Promise((resolve) => setTimeout(resolve, 1000)); // Simulate network delay

      if (email === "test@example.com" && password === "password") {
        const userData = {
          id: "123",
          name: "Demo User",
          email: email,
          token: "fake-jwt-token-for-demo", // In real app, store an actual token received from backend
        };
        setUser(userData);
        localStorage.setItem("user", JSON.stringify(userData));
        console.log("AuthContext: Login successful for", email); // Debug log
        return userData; // Return user data on success
      } else {
        console.log("AuthContext: Invalid credentials provided for", email); // Debug log
        throw new Error("Invalid email or password");
      }
    } catch (error) {
      console.error("AuthContext: Login Error:", error); // Debug log
      setUser(null); // Clear user state on failed login
      localStorage.removeItem("user"); // Ensure no invalid user data persists
      throw error; // Re-throw the error so components can handle it (e.g., display message)
    } finally {
      setLoading(false); // Always set loading to false after login attempt
      console.log("AuthContext: Login attempt finished."); // Debug log
    }
  };

  const logout = () => {
    console.log("AuthContext: Logging out user."); // Debug log
    setLoading(true); // Optionally set loading during logout if it involves async operations (like API call)
    setUser(null);
    localStorage.removeItem("user");
    // If your logout requires an API call to invalidate a session/token:
    // try { /* await fetch('/api/logout', { headers: { Authorization: `Bearer ${user.token}` } }); */ } catch (e) { console.error("Logout API failed", e); }
    setLoading(false);
  };

  const authContextValue = {
    user,
    loading, // Provide loading state to consumers
    login,
    logout,
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === null) { // Changed from 'undefined' to 'null' because createContext(null)
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};
